import{_ as a,o as t,c as n,a3 as s}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"97. Ohs Preliminary","description":"","frontmatter":{"title":"97. Ohs Preliminary","eba":"Allied Health Professionals 2021-2026","topics":["ohs"]},"headers":[],"relativePath":"ebas/allied-health/ohs/97-ohs-preliminary.md","filePath":"ebas/allied-health/ohs/97-ohs-preliminary.md"}'),r={name:"ebas/allied-health/ohs/97-ohs-preliminary.md"};function o(i,e,l,h,p,d){return t(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="_97-ohs-preliminary" tabindex="-1">97. Ohs Preliminary <a class="header-anchor" href="#_97-ohs-preliminary" aria-label="Permalink to &quot;97. Ohs Preliminary&quot;">​</a></h1><p><strong>97.1</strong> Relationship to legislation The provisions of this Part L of the Agreement shall be read and interpreted in conjunction with the OHS Act, EO Act and WIRC Act and successors, provided where there is any inconsistency between this Agreement and the legislation referred to in this subclause 97.1, the legislation prevails to the extent of any inconsistency.</p><p><strong>97.2</strong> Arrangement of this Part L This part L is arranged as follows:</p><p><strong>(a)</strong> OHS Preliminary (clause 97);</p><p><strong>(b)</strong> Industry OHS Working Group (<a href="/eba/ebas/allied-health/ohs/98-industry-ohs-working-group.html">clause 98</a>);</p><p><strong>(c)</strong> OHS Risk Management (<a href="/eba/ebas/allied-health/ohs/99-ohs-risk-management.html">clause 99</a>);</p><p><strong>(d)</strong> Incident Reporting, Investigation and Prevention (<a href="/eba/ebas/allied-health/ohs/100-incident-reporting-investigation-and-prevention.html">clause 100</a>);</p><p><strong>(e)</strong> Designated work groups (<a href="/eba/ebas/allied-health/ohs/101-designated-work-groups.html">clause 101</a>);</p><p><strong>(f)</strong> HSRs (<a href="/eba/ebas/allied-health/ohs/102-hsrs.html">clause 102</a>);</p><p><strong>(g)</strong> Occupational Violence and Aggression Prevention and Management (clause 103);</p><p><strong>(h)</strong> Workers&#39; Compensation, Rehabilitation and Return to Work (<a href="/eba/ebas/allied-health/ohs/104-workers-compensation-rehabilitation-and-return-to.html">clause 104</a>);</p><p><strong>(i)</strong> Home Visit Safety (<a href="/eba/ebas/allied-health/ohs/105-home-visit-safety.html">clause 105</a>); and</p><p><strong>(j)</strong> Facilities (<a href="/eba/ebas/allied-health/ohs/106-facilities.html">clause 106</a>).</p><p><strong>97.3</strong> Definitions For the purposes of this Part L of this Agreement:</p><p><strong>(a)</strong> DWG means designated work group as defined under the OHS Act as amended from time to time and may include employees other than Employees covered by this Agreement.</p><p><strong>(b)</strong> Incident means an event or circumstance that lead or could have lead to unintended or unnecessary harm.</p><p><strong>(c)</strong> Injury means any physical or mental injury.</p><p><strong>(d)</strong> Insurer means an authorised agent as defined by the WIRC Act.</p><p><strong>(e)</strong> OHS means occupational health and safety.</p><p><strong>(f)</strong> Workplace means workplace as defined under the OHS Act.</p>',20)])])}const m=a(r,[["render",o]]);export{c as __pageData,m as default};
